<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/comunicacion_layout.php';$pdo=obtenerConexion();$actor=(int)$_SESSION['usuario_id'];$f=['q'=>$_GET['q']??'','rol'=>$_GET['rol']??'','capacitacion'=>$_GET['capacitacion']??0,'seccion'=>$_GET['seccion']??0];$contactos=agendaComunicacion($pdo,$actor,$f);$caps=$pdo->query("SELECT id,nombre FROM asignaturas WHERE estado='activo' AND deleted_at IS NULL ORDER BY nombre")->fetchAll();$secs=$pdo->query('SELECT s.id,s.codigo,a.nombre FROM capacitacion_secciones s JOIN asignaturas a ON a.id=s.asignatura_id ORDER BY a.nombre,s.codigo')->fetchAll();comunicacionCabecera('Agenda','agenda','Contactos autorizados según tus capacitaciones y secciones.');comunicacionNav('agenda');?>
<div class="card card-rounded"><div class="card-body"><form class="row g-2 mb-4"><div class="col-lg-3"><input class="form-control" name="q" value="<?=atenea_e((string)$f['q'])?>" placeholder="Nombre o correo"></div><div class="col-lg-2"><select class="form-select" name="rol"><option value="">Todos los roles</option><?php foreach(['usuario'=>'Estudiantes','docente'=>'Docentes','admin'=>'Administración'] as$k=>$v):?><option value="<?=$k?>" <?=$f['rol']===$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="col-lg-3"><select class="form-select" name="capacitacion"><option value="">Todas las capacitaciones</option><?php foreach($caps as$c):?><option value="<?=$c['id']?>" <?=(int)$f['capacitacion']===(int)$c['id']?'selected':''?>><?=atenea_e($c['nombre'])?></option><?php endforeach;?></select></div><div class="col-lg-2"><select class="form-select" name="seccion"><option value="">Todas las secciones</option><?php foreach($secs as$s):?><option value="<?=$s['id']?>" <?=(int)$f['seccion']===(int)$s['id']?'selected':''?>><?=atenea_e($s['nombre'].' · '.$s['codigo'])?></option><?php endforeach;?></select></div><div class="col-lg-2"><button class="btn btn-primary w-100">Buscar</button></div></form><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Contacto</th><th>Rol</th><th>Acciones</th></tr></thead><tbody><?php foreach($contactos as$c):?><tr><td><strong><?=atenea_e(trim($c['nombre'].' '.$c['apellido']))?></strong><small class="d-block text-muted"><?=atenea_e($c['correo'])?></small></td><td><?=atenea_e(etiquetaRolComunicacion($c['rol']))?></td><td><form class="d-inline" method="post" action="chat-abrir.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="contacto_id" value="<?=$c['id']?>"><button class="btn btn-sm btn-primary">Abrir chat</button></form> <a class="btn btn-sm btn-outline-primary" href="redactar.php?destinatario=<?=$c['id']?>">Redactar correo</a></td></tr><?php endforeach;?><?php if(!$contactos):?><tr><td colspan="3" class="text-center py-5">No hay contactos disponibles para estos filtros.</td></tr><?php endif;?></tbody></table></div></div></div><?php comunicacionPie();
